import{_ as d,o as a,c as r,ae as e}from"./chunks/framework.BeVX27ge.js";const c=JSON.parse('{"title":"使用者管理","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/admin-users.md","filePath":"zh-TW/admin-users.md"}'),i={name:"zh-TW/admin-users.md"};function l(h,t,s,o,n,b){return a(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="使用者管理" tabindex="-1">使用者管理 <a class="header-anchor" href="#使用者管理" aria-label="Permalink to &quot;使用者管理&quot;">​</a></h1><blockquote><p>管理平台帳號、角色與權限，掌控誰可以使用哪些功能</p></blockquote><h2 id="概覽" tabindex="-1">概覽 <a class="header-anchor" href="#概覽" aria-label="Permalink to &quot;概覽&quot;">​</a></h2><p>使用者管理是管理員後台的核心功能，讓您建立、編輯、匯入和刪除平台使用者帳號，並指派適當的角色與權限。</p><blockquote><p>此功能僅對具有使用者管理權限的管理員開放。</p></blockquote><h2 id="進入方式" tabindex="-1">進入方式 <a class="header-anchor" href="#進入方式" aria-label="Permalink to &quot;進入方式&quot;">​</a></h2><ol><li>點擊頁面右上方的 <strong>管理設定圖示</strong>（齒輪）</li><li>在管理員後台中選擇「使用者管理」</li></ol><hr><h2 id="頁面結構" tabindex="-1">頁面結構 <a class="header-anchor" href="#頁面結構" aria-label="Permalink to &quot;頁面結構&quot;">​</a></h2><table tabindex="0"><thead><tr><th>區域</th><th>說明</th></tr></thead><tbody><tr><td>頁面標題列</td><td>標題「使用者管理」、篩選按鈕、新增使用者按鈕、更多操作下拉選單</td></tr><tr><td>篩選標籤列</td><td>顯示目前套用的篩選條件</td></tr><tr><td>使用者表格</td><td>所有使用者的列表</td></tr><tr><td>分頁控制列</td><td>分頁導航</td></tr></tbody></table><hr><h2 id="篩選使用者" tabindex="-1">篩選使用者 <a class="header-anchor" href="#篩選使用者" aria-label="Permalink to &quot;篩選使用者&quot;">​</a></h2><p>點擊 <strong>「篩選條件」</strong> 開啟篩選面板：</p><table tabindex="0"><thead><tr><th>篩選欄位</th><th>說明</th></tr></thead><tbody><tr><td>公司</td><td>下拉選單，篩選所屬公司</td></tr><tr><td>部門</td><td>下拉選單，需先選擇公司後才可使用（提示：「請先選擇公司以查看部門」）</td></tr><tr><td>權限</td><td>下拉選單，可選：管理員 / 使用者 / 超級使用者 / 監督者</td></tr><tr><td>電子郵件</td><td>文字搜尋，依 Email 篩選</td></tr><tr><td>姓名</td><td>文字搜尋，依姓名篩選</td></tr><tr><td>啟用狀態</td><td>下拉選單，可選：可用 / 停用</td></tr></tbody></table><p>套用篩選後，篩選標籤列會顯示每個條件的標籤，可個別移除或「清除全部」。</p><hr><h2 id="使用者表格" tabindex="-1">使用者表格 <a class="header-anchor" href="#使用者表格" aria-label="Permalink to &quot;使用者表格&quot;">​</a></h2><h3 id="表格欄位" tabindex="-1">表格欄位 <a class="header-anchor" href="#表格欄位" aria-label="Permalink to &quot;表格欄位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>欄位</th><th>說明</th></tr></thead><tbody><tr><td>公司別</td><td>使用者所屬的公司名稱</td></tr><tr><td>部門別</td><td>使用者所屬的部門名稱</td></tr><tr><td>員工編號</td><td>使用者的員工識別碼</td></tr><tr><td>電子郵件</td><td>使用者的 Email（也是登入帳號）</td></tr><tr><td>姓名</td><td>使用者的顯示名稱</td></tr><tr><td>啟用狀態</td><td>綠色圓點「可用」或紅色圓點「停用」</td></tr><tr><td>權限</td><td>使用者被指派的角色名稱</td></tr><tr><td>操作</td><td>編輯與刪除按鈕</td></tr></tbody></table><hr><h2 id="新增使用者" tabindex="-1">新增使用者 <a class="header-anchor" href="#新增使用者" aria-label="Permalink to &quot;新增使用者&quot;">​</a></h2><p>點擊 <strong>「新增使用者」</strong> 按鈕開啟新增表單。</p><h3 id="表單欄位" tabindex="-1">表單欄位 <a class="header-anchor" href="#表單欄位" aria-label="Permalink to &quot;表單欄位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>欄位</th><th>類型</th><th>必填</th><th>說明</th></tr></thead><tbody><tr><td>姓名</td><td>文字輸入</td><td>是（搭配 Email）</td><td>使用者的顯示名稱</td></tr><tr><td>電子郵件</td><td>文字輸入</td><td>是（或員工編號）</td><td>使用者的登入帳號，需為有效 Email 格式</td></tr><tr><td>員工編號</td><td>文字輸入</td><td>否（或 Email）</td><td>替代識別方式，至少需填寫 Email 或員工編號其一</td></tr><tr><td>公司</td><td>下拉選單</td><td>是</td><td>選擇使用者所屬的公司</td></tr><tr><td>部門</td><td>下拉選單</td><td>否</td><td>選擇使用者所屬的部門（需先選擇公司）</td></tr><tr><td>權限</td><td>下拉選單</td><td>是</td><td>指派角色：管理員 / 使用者 / 超級使用者 / 監督者</td></tr><tr><td>啟用狀態</td><td>開關切換</td><td>—</td><td>預設為啟用。可設為停用以暫時禁止登入</td></tr></tbody></table><h3 id="角色說明" tabindex="-1">角色說明 <a class="header-anchor" href="#角色說明" aria-label="Permalink to &quot;角色說明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th>說明</th></tr></thead><tbody><tr><td>管理員</td><td>擁有所有管理功能的存取權限，包括使用者管理、Prompt 管理、階段管理、知識庫管理</td></tr><tr><td>超級使用者</td><td>擁有進階功能權限，但部分管理功能受限</td></tr><tr><td>監督者</td><td>可監督團隊練習數據，但無法修改系統設定</td></tr><tr><td>使用者</td><td>一般使用者，僅可使用對話練習、評量報告、練習歷史等功能</td></tr></tbody></table><h3 id="驗證規則" tabindex="-1">驗證規則 <a class="header-anchor" href="#驗證規則" aria-label="Permalink to &quot;驗證規則&quot;">​</a></h3><ul><li>Email 必須是有效的電子郵件格式</li><li>Email 不可與現有使用者重複</li><li>至少需填寫 Email 或員工編號其一</li><li>所有文字輸入會進行安全性檢查</li></ul><hr><h2 id="編輯使用者" tabindex="-1">編輯使用者 <a class="header-anchor" href="#編輯使用者" aria-label="Permalink to &quot;編輯使用者&quot;">​</a></h2><p>在表格中點擊對應使用者的 <strong>「編輯」</strong> 按鈕，開啟編輯表單。</p><ul><li>表單欄位與新增相同，但會預填現有資料</li><li>修改完成後點擊儲存即可更新</li></ul><hr><h2 id="刪除使用者" tabindex="-1">刪除使用者 <a class="header-anchor" href="#刪除使用者" aria-label="Permalink to &quot;刪除使用者&quot;">​</a></h2><p>在表格中點擊對應使用者的 <strong>「刪除」</strong> 按鈕。</p><ul><li>系統會彈出確認對話框</li><li>確認後執行軟刪除（資料不會永久移除，但帳號無法再登入）</li><li>如需恢復，請聯繫系統管理員</li></ul><hr><h2 id="批次匯入使用者" tabindex="-1">批次匯入使用者 <a class="header-anchor" href="#批次匯入使用者" aria-label="Permalink to &quot;批次匯入使用者&quot;">​</a></h2><p>適用於一次性新增大量使用者。</p><h3 id="操作流程" tabindex="-1">操作流程 <a class="header-anchor" href="#操作流程" aria-label="Permalink to &quot;操作流程&quot;">​</a></h3><ol><li>點擊頁面右上方的 <strong>「更多操作」</strong> 下拉選單</li><li>選擇 <strong>「匯入使用者」</strong></li><li>點擊 <strong>「下載 CSV 模板」</strong> 取得標準範本</li><li>依範本格式填入使用者資料</li><li>點擊上傳區域或將 CSV 檔案拖曳至上傳區域</li><li>系統驗證檔案格式與內容</li><li>驗證通過後執行匯入</li></ol><h3 id="csv-檔案格式" tabindex="-1">CSV 檔案格式 <a class="header-anchor" href="#csv-檔案格式" aria-label="Permalink to &quot;CSV 檔案格式&quot;">​</a></h3><p>CSV 檔案必須包含以下欄位（依序）：</p><table tabindex="0"><thead><tr><th>欄位順序</th><th>欄位名稱</th><th>說明</th><th>範例</th></tr></thead><tbody><tr><td>1</td><td>Company Code</td><td>公司代碼</td><td>TW</td></tr><tr><td>2</td><td>Department Code</td><td>部門代碼</td><td>TW1</td></tr><tr><td>3</td><td>Employee No</td><td>員工編號</td><td>EMP001</td></tr><tr><td>4</td><td>Email</td><td>電子郵件</td><td><code>user@example.com</code></td></tr><tr><td>5</td><td>Name</td><td>使用者姓名</td><td>王小明</td></tr><tr><td>6</td><td>Role</td><td>角色名稱</td><td>user</td></tr><tr><td>7</td><td>Is Active</td><td>是否啟用</td><td>true / false</td></tr><tr><td>8</td><td>Action</td><td>操作類型</td><td>create / update</td></tr></tbody></table><p>CSV 範例：</p><div class="language-csv vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csv</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Company Code,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Department Code,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Employee No,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">Email,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Name,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">Role,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Is Active,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Action</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">TW,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TW1,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EMP001,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">user@company.com,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">王小明,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">user,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">create</span></span></code></pre></div><h3 id="常見匯入錯誤" tabindex="-1">常見匯入錯誤 <a class="header-anchor" href="#常見匯入錯誤" aria-label="Permalink to &quot;常見匯入錯誤&quot;">​</a></h3><table tabindex="0"><thead><tr><th>錯誤類型</th><th>錯誤訊息</th><th>解決方式</th></tr></thead><tbody><tr><td>檔案類型錯誤</td><td>請上傳 CSV 檔案</td><td>確認上傳的是 .csv 格式檔案</td></tr><tr><td>空檔案</td><td>CSV 檔案為空</td><td>確認檔案中有資料</td></tr><tr><td>缺少標題行</td><td>CSV 檔案必須包含標題行</td><td>確認第一行為欄位標題</td></tr><tr><td>欄位數量錯誤</td><td>CSV 標題行欄位數量不正確，必須為 N 個欄位</td><td>檢查欄位數量是否完整</td></tr><tr><td>欄位順序錯誤</td><td>CSV 標題行欄位順序或內容不正確</td><td>依照範本的欄位順序排列</td></tr><tr><td>資料列欄位不足</td><td>欄位數量不正確</td><td>確認每列資料欄位完整</td></tr></tbody></table><h3 id="匯入結果" tabindex="-1">匯入結果 <a class="header-anchor" href="#匯入結果" aria-label="Permalink to &quot;匯入結果&quot;">​</a></h3><p>匯入完成後，系統會顯示結果報告：</p><ul><li><strong>成功筆數</strong> — 成功建立或更新的使用者數量</li><li><strong>失敗筆數</strong> — 匯入失敗的資料筆數</li><li><strong>錯誤明細</strong> — 每筆失敗資料的具體錯誤原因（含行號與識別資訊）</li></ul><hr><h2 id="批次刪除使用者" tabindex="-1">批次刪除使用者 <a class="header-anchor" href="#批次刪除使用者" aria-label="Permalink to &quot;批次刪除使用者&quot;">​</a></h2><ol><li>點擊 <strong>「更多操作」</strong> → <strong>「批次刪除使用者」</strong></li><li>在彈出的對話框中選擇或篩選要刪除的使用者</li><li>確認刪除操作</li><li>系統執行批次軟刪除</li></ol><hr><h2 id="權限系統說明" tabindex="-1">權限系統說明 <a class="header-anchor" href="#權限系統說明" aria-label="Permalink to &quot;權限系統說明&quot;">​</a></h2><p>AI Coach 採用 RBAC（角色基礎存取控制）權限模型：</p><h3 id="權限類型" tabindex="-1">權限類型 <a class="header-anchor" href="#權限類型" aria-label="Permalink to &quot;權限類型&quot;">​</a></h3><p>每個功能模組可設定以下權限：</p><table tabindex="0"><thead><tr><th>權限</th><th>說明</th></tr></thead><tbody><tr><td>讀取 (Read)</td><td>可查看資料</td></tr><tr><td>新增 (Create)</td><td>可建立新資料</td></tr><tr><td>更新 (Update)</td><td>可修改既有資料</td></tr><tr><td>刪除 (Delete)</td><td>可刪除資料</td></tr></tbody></table><h3 id="功能模組" tabindex="-1">功能模組 <a class="header-anchor" href="#功能模組" aria-label="Permalink to &quot;功能模組&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模組</th><th>說明</th></tr></thead><tbody><tr><td>chat</td><td>對話練習功能</td></tr><tr><td>userDashboard</td><td>儀表板功能</td></tr><tr><td>prompt</td><td>Prompt 管理功能</td></tr><tr><td>stage</td><td>階段管理功能</td></tr><tr><td>user</td><td>使用者管理功能</td></tr><tr><td>knowledge</td><td>知識庫功能</td></tr></tbody></table><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>設定 <a href="./admin-prompts.html">Prompt 管理</a> 控制 AI 行為</li><li>管理 <a href="./admin-stages.html">銷售階段</a> 定義練習標準</li><li>維護 <a href="./admin-knowledge.html">知識庫</a> 充實學習資源</li></ul>`,65)])])}const k=d(i,[["render",l]]);export{c as __pageData,k as default};
